#!/usr/bin/env bun
/**
 * Claude Code Conversation Extractor
 *
 * Extracts all conversations from ~/.claude related to ~/antonio/mms projects
 * for fine-tuning, hooks creation, and CLAUDE.md improvement.
 *
 * Usage: bun run ./genesis/attempt6202/extract.ts
 */

import { gzipSync } from 'bun';
import { join, basename } from 'path';
import { homedir } from 'os';

// ============================================================================
// Types
// ============================================================================

interface RawMessage {
  type: 'user' | 'assistant' | 'file-history-snapshot';
  message?: {
    role: string;
    content: string | ContentBlock[];
    model?: string;
  };
  uuid?: string;
  timestamp?: string;
  sessionId?: string;
  cwd?: string;
  gitBranch?: string;
  parentUuid?: string;
}

interface ContentBlock {
  type: 'thinking' | 'text' | 'tool_use' | 'tool_result';
  thinking?: string;
  text?: string;
  name?: string;
  input?: unknown;
  content?: string;
  tool_use_id?: string;
}

interface ThinkingEntry {
  timestamp: string;
  content: string;
  messageUuid: string;
}

interface ToolCall {
  timestamp: string;
  name: string;
  input: unknown;
  toolUseId: string;
  messageUuid: string;
}

interface ExtractedMessage {
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
  uuid: string;
  model?: string;
}

interface SessionMetadata {
  sessionId: string;
  project: string;
  projectShortName: string;
  gitBranch?: string;
  firstTimestamp?: string;
  lastTimestamp?: string;
  messageCount: number;
  thinkingCount: number;
  toolCallCount: number;
}

interface ExtractedSession {
  metadata: SessionMetadata;
  messages: ExtractedMessage[];
  thinking: ThinkingEntry[];
  toolCalls: ToolCall[];
  todos: unknown[];
}

interface ProjectSummary {
  projectPath: string;
  projectShortName: string;
  sessionCount: number;
  totalMessages: number;
  totalThinking: number;
  totalToolCalls: number;
  sessions: string[];
}

interface ExtractionSummary {
  extractedAt: string;
  totalProjects: number;
  totalSessions: number;
  totalMessages: number;
  totalThinking: number;
  totalToolCalls: number;
  projects: ProjectSummary[];
}

// ============================================================================
// Configuration
// ============================================================================

const CLAUDE_DIR = join(homedir(), '.claude');
const PROJECTS_DIR = join(CLAUDE_DIR, 'projects');
const TODOS_DIR = join(CLAUDE_DIR, 'todos');
const OUTPUT_DIR = join(process.cwd(), 'genesis/attempt6202/chats');

// Projects to extract (paths containing these strings)
const MMS_PROJECT_PATTERNS = [
  'antonio-mms',
  'antonio-omms',
];

// ============================================================================
// Utilities
// ============================================================================

async function saveGzipped(data: unknown, path: string): Promise<void> {
  const json = JSON.stringify(data, null, 2);
  const compressed = gzipSync(Buffer.from(json));
  await Bun.write(path, compressed);
}

function getProjectShortName(projectPath: string): string {
  // Extract short name from path like "-Users-anotonio-silva-antonio-mms-system"
  const parts = projectPath.split('-antonio-');
  if (parts.length > 1) {
    return parts[1].replace(/-/g, '/');
  }
  return projectPath;
}

function extractTextContent(content: string | ContentBlock[]): string {
  if (typeof content === 'string') {
    return content;
  }

  const textParts: string[] = [];
  for (const block of content) {
    if (block.type === 'text' && block.text) {
      textParts.push(block.text);
    } else if (block.type === 'tool_result' && typeof block.content === 'string') {
      textParts.push(`[Tool Result]: ${block.content.slice(0, 500)}...`);
    }
  }
  return textParts.join('\n');
}

function extractThinking(content: string | ContentBlock[], messageUuid: string, timestamp: string): ThinkingEntry[] {
  if (typeof content === 'string') {
    return [];
  }

  const thinking: ThinkingEntry[] = [];
  for (const block of content) {
    if (block.type === 'thinking' && block.thinking) {
      thinking.push({
        timestamp,
        content: block.thinking,
        messageUuid,
      });
    }
  }
  return thinking;
}

function extractToolCalls(content: string | ContentBlock[], messageUuid: string, timestamp: string): ToolCall[] {
  if (typeof content === 'string') {
    return [];
  }

  const toolCalls: ToolCall[] = [];
  for (const block of content) {
    if (block.type === 'tool_use' && block.name) {
      toolCalls.push({
        timestamp,
        name: block.name,
        input: block.input,
        toolUseId: block.tool_use_id || '',
        messageUuid,
      });
    }
  }
  return toolCalls;
}

// ============================================================================
// Core Functions
// ============================================================================

async function findMMSProjects(): Promise<string[]> {
  const projects: string[] = [];

  try {
    const entries = await Array.fromAsync(
      new Bun.Glob('*').scan({ cwd: PROJECTS_DIR, onlyFiles: false })
    );

    for (const entry of entries) {
      for (const pattern of MMS_PROJECT_PATTERNS) {
        if (entry.includes(pattern)) {
          projects.push(entry);
          break;
        }
      }
    }
  } catch (error) {
    console.error('Error scanning projects directory:', error);
  }

  return projects.sort();
}

async function getSessionFiles(projectDir: string): Promise<string[]> {
  const fullPath = join(PROJECTS_DIR, projectDir);
  const sessions: string[] = [];

  try {
    const entries = await Array.fromAsync(
      new Bun.Glob('*.jsonl').scan({ cwd: fullPath, onlyFiles: true })
    );
    sessions.push(...entries);
  } catch (error) {
    console.error(`Error scanning sessions in ${projectDir}:`, error);
  }

  return sessions.sort();
}

async function loadTodos(sessionId: string): Promise<unknown[]> {
  const todoFile = join(TODOS_DIR, `${sessionId}-agent-${sessionId}.json`);

  try {
    const file = Bun.file(todoFile);
    if (await file.exists()) {
      return await file.json();
    }
  } catch {
    // Todos file doesn't exist or is invalid
  }

  return [];
}

async function extractSession(projectDir: string, sessionFile: string): Promise<ExtractedSession | null> {
  const fullPath = join(PROJECTS_DIR, projectDir, sessionFile);
  const sessionId = basename(sessionFile, '.jsonl');

  try {
    const content = await Bun.file(fullPath).text();
    const lines = content.split('\n').filter(line => line.trim());

    const messages: ExtractedMessage[] = [];
    const thinking: ThinkingEntry[] = [];
    const toolCalls: ToolCall[] = [];
    let gitBranch: string | undefined;
    let firstTimestamp: string | undefined;
    let lastTimestamp: string | undefined;

    for (const line of lines) {
      try {
        const raw: RawMessage = JSON.parse(line);

        // Skip file-history-snapshot entries
        if (raw.type === 'file-history-snapshot') {
          continue;
        }

        // Track git branch
        if (raw.gitBranch && !gitBranch) {
          gitBranch = raw.gitBranch;
        }

        // Track timestamps
        if (raw.timestamp) {
          if (!firstTimestamp) {
            firstTimestamp = raw.timestamp;
          }
          lastTimestamp = raw.timestamp;
        }

        // Process user messages
        if (raw.type === 'user' && raw.message) {
          const content = typeof raw.message.content === 'string'
            ? raw.message.content
            : extractTextContent(raw.message.content);

          messages.push({
            role: 'user',
            content,
            timestamp: raw.timestamp || '',
            uuid: raw.uuid || '',
          });
        }

        // Process assistant messages
        if (raw.type === 'assistant' && raw.message) {
          const content = extractTextContent(raw.message.content);
          const msgThinking = extractThinking(
            raw.message.content,
            raw.uuid || '',
            raw.timestamp || ''
          );
          const msgToolCalls = extractToolCalls(
            raw.message.content,
            raw.uuid || '',
            raw.timestamp || ''
          );

          // Only add message if it has text content (not just tool calls)
          if (content.trim()) {
            messages.push({
              role: 'assistant',
              content,
              timestamp: raw.timestamp || '',
              uuid: raw.uuid || '',
              model: raw.message.model,
            });
          }

          thinking.push(...msgThinking);
          toolCalls.push(...msgToolCalls);
        }
      } catch {
        // Skip invalid JSON lines
      }
    }

    // Skip sessions with no messages
    if (messages.length === 0) {
      return null;
    }

    // Load todos
    const todos = await loadTodos(sessionId);

    const metadata: SessionMetadata = {
      sessionId,
      project: projectDir,
      projectShortName: getProjectShortName(projectDir),
      gitBranch,
      firstTimestamp,
      lastTimestamp,
      messageCount: messages.length,
      thinkingCount: thinking.length,
      toolCallCount: toolCalls.length,
    };

    return {
      metadata,
      messages,
      thinking,
      toolCalls,
      todos,
    };
  } catch (error) {
    console.error(`Error extracting session ${sessionFile}:`, error);
    return null;
  }
}

async function saveSession(session: ExtractedSession, outputDir: string): Promise<void> {
  const sessionDir = join(outputDir, `session-${session.metadata.sessionId}`);
  await Bun.write(join(sessionDir, '.gitkeep'), ''); // Ensure directory exists

  // Save metadata
  await saveGzipped(session.metadata, join(sessionDir, 'metadata.json.gz'));

  // Save conversation
  await saveGzipped(session.messages, join(sessionDir, 'conversation.json.gz'));

  // Save thinking (separate file)
  if (session.thinking.length > 0) {
    await saveGzipped(session.thinking, join(sessionDir, 'thinking.json.gz'));
  }

  // Save tool calls
  if (session.toolCalls.length > 0) {
    await saveGzipped(session.toolCalls, join(sessionDir, 'tools.json.gz'));
  }

  // Save todos
  if (session.todos.length > 0) {
    await saveGzipped(session.todos, join(sessionDir, 'todos.json.gz'));
  }
}

async function extractProject(projectDir: string): Promise<ProjectSummary> {
  const projectShortName = getProjectShortName(projectDir);
  const outputDir = join(OUTPUT_DIR, projectShortName.replace(/\//g, '-'));

  console.log(`\n📁 Processing project: ${projectShortName}`);

  const sessionFiles = await getSessionFiles(projectDir);
  console.log(`   Found ${sessionFiles.length} sessions`);

  let totalMessages = 0;
  let totalThinking = 0;
  let totalToolCalls = 0;
  const sessions: string[] = [];

  for (let i = 0; i < sessionFiles.length; i++) {
    const sessionFile = sessionFiles[i];
    const session = await extractSession(projectDir, sessionFile);

    if (session) {
      await saveSession(session, outputDir);

      totalMessages += session.metadata.messageCount;
      totalThinking += session.metadata.thinkingCount;
      totalToolCalls += session.metadata.toolCallCount;
      sessions.push(session.metadata.sessionId);

      // Progress indicator every 50 sessions
      if ((i + 1) % 50 === 0) {
        console.log(`   ... processed ${i + 1}/${sessionFiles.length} sessions`);
      }
    }
  }

  console.log(`   ✅ Extracted ${sessions.length} sessions with content`);
  console.log(`      Messages: ${totalMessages}, Thinking: ${totalThinking}, Tool calls: ${totalToolCalls}`);

  return {
    projectPath: projectDir,
    projectShortName,
    sessionCount: sessions.length,
    totalMessages,
    totalThinking,
    totalToolCalls,
    sessions,
  };
}

// ============================================================================
// Main
// ============================================================================

async function main(): Promise<void> {
  console.log('🚀 Claude Code Conversation Extractor');
  console.log('=====================================');
  console.log(`📂 Source: ${PROJECTS_DIR}`);
  console.log(`📂 Output: ${OUTPUT_DIR}`);

  // Find all MMS projects
  const projects = await findMMSProjects();
  console.log(`\n📋 Found ${projects.length} MMS projects:`);
  for (const p of projects) {
    console.log(`   - ${getProjectShortName(p)}`);
  }

  // Extract each project
  const projectSummaries: ProjectSummary[] = [];

  for (const projectDir of projects) {
    const summary = await extractProject(projectDir);
    projectSummaries.push(summary);
  }

  // Generate summary
  const totalSessions = projectSummaries.reduce((acc, p) => acc + p.sessionCount, 0);
  const totalMessages = projectSummaries.reduce((acc, p) => acc + p.totalMessages, 0);
  const totalThinking = projectSummaries.reduce((acc, p) => acc + p.totalThinking, 0);
  const totalToolCalls = projectSummaries.reduce((acc, p) => acc + p.totalToolCalls, 0);

  const summary: ExtractionSummary = {
    extractedAt: new Date().toISOString(),
    totalProjects: projects.length,
    totalSessions,
    totalMessages,
    totalThinking,
    totalToolCalls,
    projects: projectSummaries,
  };

  // Save summary (uncompressed for easy reading)
  await Bun.write(
    join(OUTPUT_DIR, 'summary.json'),
    JSON.stringify(summary, null, 2)
  );

  console.log('\n=====================================');
  console.log('📊 Extraction Summary:');
  console.log(`   Projects: ${summary.totalProjects}`);
  console.log(`   Sessions: ${summary.totalSessions}`);
  console.log(`   Messages: ${summary.totalMessages}`);
  console.log(`   Thinking blocks: ${summary.totalThinking}`);
  console.log(`   Tool calls: ${summary.totalToolCalls}`);
  console.log(`\n✅ Extraction complete! Output saved to: ${OUTPUT_DIR}`);
}

// Run
main().catch(console.error);

