#!/usr/bin/env bun
/**
 * Claude Code Conversation Extractor (Flat Text Mode)
 *
 * Extracts conversations from ~/.claude related to ~/antonio/mms projects
 * as plain text files for easy reading and analysis.
 *
 * Output format: project-YYYYMMDDHHMM.txt
 * Example: mms-system-202512161154.txt
 *
 * Usage: bun run ./genesis/attempt6202/extract.ts
 */

import { join, basename } from 'path';
import { homedir } from 'os';

// ============================================================================
// Types
// ============================================================================

interface RawMessage {
  type: 'user' | 'assistant' | 'file-history-snapshot';
  message?: {
    role: string;
    content: string | ContentBlock[];
    model?: string;
  };
  timestamp?: string;
}

interface ContentBlock {
  type: 'thinking' | 'text' | 'tool_use' | 'tool_result';
  text?: string;
}

interface SimpleMessage {
  role: 'user' | 'assistant';
  content: string;
  timestamp: string;
}

// ============================================================================
// Configuration
// ============================================================================

const CLAUDE_DIR = join(homedir(), '.claude');
const PROJECTS_DIR = join(CLAUDE_DIR, 'projects');
const OUTPUT_DIR = join(process.cwd(), 'genesis/attempt6202/chats');

const MMS_PROJECT_PATTERNS = [
  'antonio-mms',
  'antonio-omms',
];

// ============================================================================
// Utilities
// ============================================================================

function getProjectShortName(projectPath: string): string {
  const parts = projectPath.split('-antonio-');
  if (parts.length > 1) {
    return parts[1].replace(/-/g, '-').replace(/\//g, '-');
  }
  return projectPath;
}

function extractTextContent(content: string | ContentBlock[]): string {
  if (typeof content === 'string') {
    return content;
  }

  const textParts: string[] = [];
  for (const block of content) {
    if (block.type === 'text' && block.text) {
      textParts.push(block.text);
    }
  }
  return textParts.join('\n');
}

function formatTimestamp(isoTimestamp: string): string {
  // Convert "2025-12-16T11:54:44.343Z" to "202512161154"
  const date = new Date(isoTimestamp);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  const hours = String(date.getHours()).padStart(2, '0');
  const minutes = String(date.getMinutes()).padStart(2, '0');
  return `${year}${month}${day}${hours}${minutes}`;
}

function formatMessageForText(msg: SimpleMessage): string {
  const roleLabel = msg.role === 'user' ? '👤 USER' : '🤖 ASSISTANT';
  const separator = '─'.repeat(60);
  return `${separator}\n${roleLabel}\n${separator}\n${msg.content}\n`;
}

// ============================================================================
// Core Functions
// ============================================================================

async function findMMSProjects(): Promise<string[]> {
  const projects: string[] = [];

  try {
    const entries = await Array.fromAsync(
      new Bun.Glob('*').scan({ cwd: PROJECTS_DIR, onlyFiles: false })
    );

    for (const entry of entries) {
      for (const pattern of MMS_PROJECT_PATTERNS) {
        if (entry.includes(pattern)) {
          projects.push(entry);
          break;
        }
      }
    }
  } catch (error) {
    console.error('Error scanning projects directory:', error);
  }

  return projects.sort();
}

async function getSessionFiles(projectDir: string): Promise<string[]> {
  const fullPath = join(PROJECTS_DIR, projectDir);
  const sessions: string[] = [];

  try {
    const entries = await Array.fromAsync(
      new Bun.Glob('*.jsonl').scan({ cwd: fullPath, onlyFiles: true })
    );
    sessions.push(...entries);
  } catch (error) {
    console.error(`Error scanning sessions in ${projectDir}:`, error);
  }

  return sessions.sort();
}

async function extractSession(projectDir: string, sessionFile: string): Promise<{ messages: SimpleMessage[]; firstTimestamp: string } | null> {
  const fullPath = join(PROJECTS_DIR, projectDir, sessionFile);

  try {
    const content = await Bun.file(fullPath).text();
    const lines = content.split('\n').filter(line => line.trim());

    const messages: SimpleMessage[] = [];
    let firstTimestamp = '';

    for (const line of lines) {
      try {
        const raw: RawMessage = JSON.parse(line);

        if (raw.type === 'file-history-snapshot') {
          continue;
        }

        if (raw.timestamp && !firstTimestamp) {
          firstTimestamp = raw.timestamp;
        }

        if (raw.type === 'user' && raw.message) {
          const text = typeof raw.message.content === 'string'
            ? raw.message.content
            : extractTextContent(raw.message.content);

          if (text.trim()) {
            messages.push({
              role: 'user',
              content: text,
              timestamp: raw.timestamp || '',
            });
          }
        }

        if (raw.type === 'assistant' && raw.message) {
          const text = extractTextContent(raw.message.content);

          if (text.trim()) {
            messages.push({
              role: 'assistant',
              content: text,
              timestamp: raw.timestamp || '',
            });
          }
        }
      } catch {
        // Skip invalid JSON lines
      }
    }

    if (messages.length === 0) {
      return null;
    }

    return { messages, firstTimestamp };
  } catch (error) {
    console.error(`Error extracting session ${sessionFile}:`, error);
    return null;
  }
}

function formatConversationAsText(
  projectName: string,
  sessionId: string,
  messages: SimpleMessage[],
  firstTimestamp: string
): string {
  const header = `
╔══════════════════════════════════════════════════════════════════════════════╗
║ CLAUDE CODE CONVERSATION                                                      ║
╠══════════════════════════════════════════════════════════════════════════════╣
║ Project:   ${projectName.padEnd(64)}║
║ Session:   ${sessionId.padEnd(64)}║
║ Started:   ${firstTimestamp.padEnd(64)}║
║ Messages:  ${String(messages.length).padEnd(64)}║
╚══════════════════════════════════════════════════════════════════════════════╝

`;

  const body = messages.map(formatMessageForText).join('\n');

  return header + body;
}

async function extractProject(projectDir: string): Promise<{ sessionCount: number; messageCount: number }> {
  const projectShortName = getProjectShortName(projectDir);

  console.log(`\n📁 Processing project: ${projectShortName}`);

  const sessionFiles = await getSessionFiles(projectDir);
  console.log(`   Found ${sessionFiles.length} sessions`);

  let totalMessages = 0;
  let savedCount = 0;

  for (let i = 0; i < sessionFiles.length; i++) {
    const sessionFile = sessionFiles[i];
    const sessionId = basename(sessionFile, '.jsonl');
    const result = await extractSession(projectDir, sessionFile);

    if (result && result.messages.length > 0) {
      const { messages, firstTimestamp } = result;

      // Generate filename: project-YYYYMMDDHHMM.txt
      const timestamp = formatTimestamp(firstTimestamp || new Date().toISOString());
      const filename = `${projectShortName}-${timestamp}.txt`;
      const outputPath = join(OUTPUT_DIR, filename);

      // Format and save
      const text = formatConversationAsText(projectShortName, sessionId, messages, firstTimestamp);
      await Bun.write(outputPath, text);

      totalMessages += messages.length;
      savedCount++;
    }

    // Progress indicator every 100 sessions
    if ((i + 1) % 100 === 0) {
      console.log(`   ... processed ${i + 1}/${sessionFiles.length} sessions`);
    }
  }

  console.log(`   ✅ Saved ${savedCount} conversations (${totalMessages} messages)`);

  return { sessionCount: savedCount, messageCount: totalMessages };
}

// ============================================================================
// Main
// ============================================================================

async function main(): Promise<void> {
  console.log('🚀 Claude Code Conversation Extractor (Flat Text Mode)');
  console.log('======================================================');
  console.log(`📂 Source: ${PROJECTS_DIR}`);
  console.log(`📂 Output: ${OUTPUT_DIR}`);

  // Find all MMS projects
  const projects = await findMMSProjects();
  console.log(`\n📋 Found ${projects.length} MMS projects`);

  // Extract each project
  let totalSessions = 0;
  let totalMessages = 0;

  for (const projectDir of projects) {
    const { sessionCount, messageCount } = await extractProject(projectDir);
    totalSessions += sessionCount;
    totalMessages += messageCount;
  }

  console.log('\n======================================================');
  console.log('📊 Extraction Summary:');
  console.log(`   Projects: ${projects.length}`);
  console.log(`   Conversations: ${totalSessions}`);
  console.log(`   Messages: ${totalMessages}`);
  console.log(`\n✅ Done! Files saved to: ${OUTPUT_DIR}`);
}

// Run
main().catch(console.error);

