#!/usr/bin/env bun
/**
 * Claude Code Conversation Extractor - Flat Text Format
 * Extracts conversations as plain text files for AI training
 */

import { join, basename } from 'path';
import { homedir } from 'os';

const CLAUDE_DIR = join(homedir(), '.claude');
const PROJECTS_DIR = join(CLAUDE_DIR, 'projects');
const OUTPUT_DIR = join(process.cwd(), 'genesis/attempt6202/chats');

const MMS_PROJECT_PATTERNS = ['antonio-mms', 'antonio-omms'];

interface RawMessage {
  type: 'user' | 'assistant' | 'file-history-snapshot';
  message?: {
    role: string;
    content: string | ContentBlock[];
  };
  timestamp?: string;
}

interface ContentBlock {
  type: 'thinking' | 'text' | 'tool_use' | 'tool_result';
  text?: string;
}

function getProjectShortName(projectPath: string): string {
  const parts = projectPath.split('-antonio-');
  if (parts.length > 1) {
    return parts[1].replace(/-/g, '-').replace(/\//g, '-');
  }
  return projectPath;
}

function extractTextContent(content: string | ContentBlock[]): string {
  if (typeof content === 'string') return content;
  const parts: string[] = [];
  for (const block of content) {
    if (block.type === 'text' && block.text) {
      parts.push(block.text);
    }
  }
  return parts.join('\n');
}

function formatTimestamp(ts: string): string {
  const d = new Date(ts);
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  const h = String(d.getHours()).padStart(2, '0');
  const min = String(d.getMinutes()).padStart(2, '0');
  return `${y}${m}${day}${h}${min}`;
}

async function findMMSProjects(): Promise<string[]> {
  const projects: string[] = [];
  try {
    const entries = await Array.fromAsync(
      new Bun.Glob('*').scan({ cwd: PROJECTS_DIR, onlyFiles: false })
    );
    for (const entry of entries) {
      for (const pattern of MMS_PROJECT_PATTERNS) {
        if (entry.includes(pattern)) {
          projects.push(entry);
          break;
        }
      }
    }
  } catch (e) {
    console.error('Error scanning projects:', e);
  }
  return projects.sort();
}

async function getSessionFiles(projectDir: string): Promise<string[]> {
  const fullPath = join(PROJECTS_DIR, projectDir);
  try {
    const entries = await Array.fromAsync(
      new Bun.Glob('*.jsonl').scan({ cwd: fullPath, onlyFiles: true })
    );
    return entries.sort();
  } catch {
    return [];
  }
}

async function extractSession(projectDir: string, sessionFile: string): Promise<{ text: string; timestamp: string } | null> {
  const fullPath = join(PROJECTS_DIR, projectDir, sessionFile);

  try {
    const content = await Bun.file(fullPath).text();
    const lines = content.split('\n').filter(line => line.trim());

    const messages: string[] = [];
    let firstTimestamp = '';

    for (const line of lines) {
      try {
        const raw: RawMessage = JSON.parse(line);
        if (raw.type === 'file-history-snapshot') continue;

        if (raw.timestamp && !firstTimestamp) {
          firstTimestamp = raw.timestamp;
        }

        if (raw.type === 'user' && raw.message) {
          const text = typeof raw.message.content === 'string'
            ? raw.message.content
            : extractTextContent(raw.message.content);
          if (text.trim()) {
            messages.push(`USER:\n${text.trim()}`);
          }
        }

        if (raw.type === 'assistant' && raw.message) {
          const text = extractTextContent(raw.message.content);
          if (text.trim()) {
            messages.push(`ASSISTANT:\n${text.trim()}`);
          }
        }
      } catch {
        // skip invalid lines
      }
    }

    if (messages.length === 0) return null;

    return {
      text: messages.join('\n\n---\n\n'),
      timestamp: firstTimestamp || new Date().toISOString(),
    };
  } catch {
    return null;
  }
}

async function main(): Promise<void> {
  console.log('Claude Code Extractor - Flat Text');
  console.log(`Source: ${PROJECTS_DIR}`);
  console.log(`Output: ${OUTPUT_DIR}`);

  await Bun.write(join(OUTPUT_DIR, '.gitkeep'), '');

  const projects = await findMMSProjects();
  console.log(`Found ${projects.length} MMS projects`);

  let totalFiles = 0;
  let totalMessages = 0;

  for (const projectDir of projects) {
    const projectName = getProjectShortName(projectDir);
    const sessionFiles = await getSessionFiles(projectDir);

    console.log(`\n${projectName}: ${sessionFiles.length} sessions`);

    for (const sessionFile of sessionFiles) {
      const result = await extractSession(projectDir, sessionFile);
      if (!result) continue;

      const ts = formatTimestamp(result.timestamp);
      const sessionId = basename(sessionFile, '.jsonl').slice(0, 8);
      const filename = `${projectName}-${ts}-${sessionId}.txt`;

      await Bun.write(join(OUTPUT_DIR, filename), result.text);

      const msgCount = (result.text.match(/^(USER|ASSISTANT):/gm) || []).length;
      totalMessages += msgCount;
      totalFiles++;
    }
  }

  console.log(`\nDone: ${totalFiles} files, ${totalMessages} messages`);
}

main().catch(console.error);

