#!/usr/bin/env bun
/**
 * Claude Code Conversation Extractor - Flat JSONL Format
 *
 * Outputs a single JSONL file optimized for AI training/processing.
 * Each line is a complete conversation turn.
 */

import { join, basename } from 'path';
import { homedir } from 'os';

// Types
interface RawMessage {
  type: 'user' | 'assistant' | 'file-history-snapshot';
  message?: {
    role: string;
    content: string | ContentBlock[];
    model?: string;
  };
  uuid?: string;
  timestamp?: string;
  sessionId?: string;
  cwd?: string;
  gitBranch?: string;
}

interface ContentBlock {
  type: 'thinking' | 'text' | 'tool_use' | 'tool_result';
  thinking?: string;
  text?: string;
  name?: string;
  input?: unknown;
  content?: string;
}

interface ConversationTurn {
  project: string;
  session: string;
  role: 'user' | 'assistant';
  content: string;
  model?: string;
}

// Config
const CLAUDE_DIR = join(homedir(), '.claude');
const PROJECTS_DIR = join(CLAUDE_DIR, 'projects');
const OUTPUT_FILE = join(process.cwd(), 'genesis/attempt6202/chats/conversations.jsonl');

const MMS_PROJECT_PATTERNS = ['antonio-mms', 'antonio-omms'];

// Utils
function getProjectShortName(projectPath: string): string {
  const parts = projectPath.split('-antonio-');
  return parts.length > 1 ? parts[1].replace(/-/g, '/') : projectPath;
}

function extractTextContent(content: string | ContentBlock[]): string {
  if (typeof content === 'string') return content;

  const parts: string[] = [];
  for (const block of content) {
    if (block.type === 'text' && block.text) {
      parts.push(block.text);
    }
  }
  return parts.join('\n');
}

async function findMMSProjects(): Promise<string[]> {
  const projects: string[] = [];
  const entries = await Array.fromAsync(
    new Bun.Glob('*').scan({ cwd: PROJECTS_DIR, onlyFiles: false })
  );

  for (const entry of entries) {
    if (MMS_PROJECT_PATTERNS.some(p => entry.includes(p))) {
      projects.push(entry);
    }
  }
  return projects.sort();
}

async function getSessionFiles(projectDir: string): Promise<string[]> {
  const fullPath = join(PROJECTS_DIR, projectDir);
  const entries = await Array.fromAsync(
    new Bun.Glob('*.jsonl').scan({ cwd: fullPath, onlyFiles: true })
  );
  return entries.sort();
}

async function* extractTurns(projectDir: string, sessionFile: string): AsyncGenerator<ConversationTurn> {
  const fullPath = join(PROJECTS_DIR, projectDir, sessionFile);
  const sessionId = basename(sessionFile, '.jsonl');
  const project = getProjectShortName(projectDir);

  const content = await Bun.file(fullPath).text();
  const lines = content.split('\n').filter(line => line.trim());

  for (const line of lines) {
    try {
      const raw: RawMessage = JSON.parse(line);

      if (raw.type === 'file-history-snapshot') continue;

      if (raw.type === 'user' && raw.message) {
        const text = typeof raw.message.content === 'string'
          ? raw.message.content
          : extractTextContent(raw.message.content);

        if (text.trim()) {
          yield { project, session: sessionId, role: 'user', content: text.trim() };
        }
      }

      if (raw.type === 'assistant' && raw.message) {
        const text = extractTextContent(raw.message.content);
        if (text.trim()) {
          yield {
            project,
            session: sessionId,
            role: 'assistant',
            content: text.trim(),
            model: raw.message.model
          };
        }
      }
    } catch {
      // skip invalid lines
    }
  }
}

async function main(): Promise<void> {
  console.log('Extracting conversations to JSONL...');

  const projects = await findMMSProjects();
  console.log(`Found ${projects.length} projects`);

  const outputFile = Bun.file(OUTPUT_FILE);
  const writer = outputFile.writer();

  let totalTurns = 0;
  let totalSessions = 0;

  for (const projectDir of projects) {
    const projectName = getProjectShortName(projectDir);
    const sessionFiles = await getSessionFiles(projectDir);

    for (const sessionFile of sessionFiles) {
      let sessionHasTurns = false;

      for await (const turn of extractTurns(projectDir, sessionFile)) {
        writer.write(JSON.stringify(turn) + '\n');
        totalTurns++;
        sessionHasTurns = true;
      }

      if (sessionHasTurns) totalSessions++;
    }

    console.log(`  ${projectName}: ${sessionFiles.length} sessions`);
  }

  await writer.end();

  const stats = await Bun.file(OUTPUT_FILE).stat();
  const sizeMB = (stats?.size || 0) / 1024 / 1024;

  console.log(`\nDone:`);
  console.log(`  Sessions: ${totalSessions}`);
  console.log(`  Turns: ${totalTurns}`);
  console.log(`  Size: ${sizeMB.toFixed(2)} MB`);
  console.log(`  Output: ${OUTPUT_FILE}`);
}

main().catch(console.error);

